import React, { useEffect, useState } from "react";
import axios from "axios";
import { startTracking, getData } from "./tracker";

const questions = [
  { prompt: "1 + 1 = ?", answer: "2" },
  { prompt: "5 - 2 = ?", answer: "3" },
  { prompt: "3 + 4 = ?", answer: "7" },
  { prompt: "10 - 3 = ?", answer: "7" },
  { prompt: "2 + 2 = ?", answer: "4" },
  { prompt: "6 - 1 = ?", answer: "5" },
  { prompt: "4 + 3 = ?", answer: "7" },
  { prompt: "9 - 4 = ?", answer: "5" },
];

function LetterGame({ onNext }) {
  const [answers, setAnswers] = useState(Array(questions.length).fill(""));
  const [status, setStatus] = useState("");

  useEffect(() => {
    startTracking();
  }, []);

  const handleChange = (index, value) => {
    const next = [...answers];
    next[index] = value;
    setAnswers(next);
  };

  const finishGame = async () => {
    const isCorrect = questions.every(
      (q, i) => q.answer.toLowerCase() === answers[i].trim().toLowerCase()
    );

    if (!isCorrect) {
      setStatus("Please try again — check your answers and make sure all blanks are filled.");
      return;
    }

    setStatus("Excellent! All answers are correct! Saving progress...");

    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        studentId: "child_01",
        activity: "number_math_activity",
        answers,
        totalQuestions: questions.length,
        ...data,
      });
    } catch (err) {
      console.error("Number Game save failed:", err);
      alert("Progress could not be saved to the server. Continuing anyway.");
    }

    if (onNext) onNext();
  };

  const style = {
    textAlign: "center",
    backgroundColor: "#FFF8DC",
    height: "100vh",
    paddingTop: "50px",
    overflowY: "auto",
  };

  return (
    <div style={style}>
      <h1>Number Math Activity 🔢</h1>
      <p style={{ fontSize: "18px" }}>Solve each math problem and fill in the answer.</p>

      <div style={{ maxWidth: "500px", margin: "0 auto", textAlign: "left" }}>
        {questions.map((question, index) => (
          <div key={index} style={{ marginBottom: "16px" }}>
            <label style={{ display: "block", fontSize: "20px", marginBottom: "8px", fontWeight: 600 }}>
              {index + 1}. {question.prompt}
            </label>
            <input
              type="text"
              value={answers[index]}
              onChange={(e) => handleChange(index, e.target.value)}
              placeholder="Type answer here"
              style={{
                width: "100%",
                padding: "10px",
                fontSize: "18px",
                borderRadius: "8px",
                border: "2px solid #ddd",
              }}
            />
          </div>
        ))}
      </div>

      {status && (
        <p style={{ color: status.includes("Excellent") ? "green" : "red", fontWeight: 600, fontSize: "16px" }}>
          {status}
        </p>
      )}

      <button onClick={finishGame} style={{ fontSize: "20px", marginTop: "20px", padding: "10px 30px" }}>
        Submit Answers
      </button>
    </div>
  );
}

export default LetterGame;
